where.if:

AND (a.model_name LIKE #{keywordPattern}
    OR a.model_no LIKE #{keywordPattern}
    OR (a.in_params IS NOT NULL AND a.in_params LIKE #{keywordPattern}))

mapper.select:
SELECT COUNT(1) FROM byai_aimodel
WHERE model_name = #{modelName}

    AND model_id != #{excludeModelId}

select model_id, model_type, model_name, model_no, status, is_support_chart, is_deepthink, max_content_token, in_params, CASE WHEN d.obj_id IS NOT NULL THEN 1 ELSE 0 END AS is_default from byai_aimodel a inner join byai_tag_relation b on a.model_id = b.obj_id left join byai_tag_relation d on a.model_id = d.obj_id and d.obj_type = 'AI_MODEL' and d.tag_id = 3
and b.obj_type = 'AI_MODEL'
AND a.status = #{status}
AND b.tag_id = #{tagId}

select model_id, model_type, model_name, model_no, url, auth_token, status, is_support_chart, is_deepthink, max_content_token, in_params, CASE WHEN d.obj_id IS NOT NULL THEN 1 ELSE 0 END AS is_default from byai_aimodel a inner join byai_tag_relation b on a.model_id = b.obj_id left join byai_tag_relation d on a.model_id = d.obj_id and d.obj_type = 'AI_MODEL' and d.tag_id = 3
and b.obj_type = 'AI_MODEL'
AND a.status = #{status}
AND b.tag_id = #{tagId}
